import React from "react";

function AppointmentRequests() {
  return (
    <section className="card">
      <h2>Appointment Requests</h2>
      <p className="hint">
        This section is intentionally left as a placeholder. Add appointment endpoints in
        `doctor_service` (or connect to `appointment_service`) before wiring this UI.
      </p>
    </section>
  );
}

export default AppointmentRequests;
